(function(){var loadHandler=window['sl_{9428E942-AA68-43AB-8023-608914E6704C}'];loadHandler&&loadHandler(1, '<div id="spr0_20581c0"><div id="spr1_20581c0" class="kern slide"><img id="img5_20581c0" src="data:image/png;base64," width="1280px" height="720px" alt="" style="left:0px;top:0px;"/><div id="spr3_20581c0"><img id="img0_20581c0" src="data:image/png;base64," width="1279.5" height="720" alt="Celestia-R1---OverlayContentHD.png" style="left:0.062px;top:-0.07px;"/></div></div><div id="spr2_20581c0" class="kern slide"><div id="spr4_20581c0"><img id="img1_20581c0" src="data:image/png;base64," width="1280.25" height="720" alt="Topview of mint green workspace with laptop, coffee, notebook, pen, glasses, and mouse" style="left:-0.094px;"/></div><div id="spr5_20581c0" style="left:35.25px;top:89.25px;"><img id="img2_20581c0" src="data:image/png;base64," width="738" height="612" alt=""/></div><div id="svg6_20581c0" style="left:34.216px;top:21.111px;"><svg width="740" height="92" viewBox="-2.833 -2.833 740 92"><path fill="#561f60" stroke="#37144c" stroke-width="5.667" stroke-linecap="butt" stroke-linejoin="round" d="M2.833,2.833 h728.551 v80 h-728.551 Z"/></svg></div><div id="spr6_20581c0" style="left:37.049px;top:23.944px;"><div style="width:0px;"><span id="txt0_20581c0" data-width="118.398438" style="left:307.942px;top:18.795px;">ALPHA CORP.</span></div><div style="width:0px;"><span id="txt1_20581c0" data-width="241.654938" style="left:246.109px;top:51.221px;">INTERNAL MEMORANDUM — CONFIDENTIAL</span></div></div><div id="spr7_20581c0" style="left:53.155px;top:113.366px;"><div style="width:0px;"><span id="txt2_20581c0" class="nokern relpos" data-width="39.462891" style="left:9.6px;top:8.676px;">FROM:      </span> <span id="txt3_20581c0" class="nokern relpos" data-width="176.654297" style="left:9.593px;top:9.192px;">Office of the Chief Information Security Officer</span></div><div style="width:0px;"><span id="txt4_20581c0" class="nokern relpos" data-width="42.287109" style="left:9.6px;top:27.343px;">TO:            </span> <span id="txt5_20581c0" class="nokern relpos" data-width="176.074219" style="left:9.593px;top:27.859px;">All Personnel, Contractors, and Executive Staff</span></div><div style="width:0px;"><span id="txt6_20581c0" class="nokern relpos" data-width="37.511719" style="left:9.6px;top:46.01px;">DATE:      </span> <span id="txt7_20581c0" class="nokern relpos" data-width="48.662109" style="left:9.593px;top:46.525px;">May 10, 2026</span></div><div style="width:0px;"><span id="txt8_20581c0" class="nokern relpos" data-width="42.152344" style="left:9.6px;top:64.676px;">RE:            </span> <span id="txt9_20581c0" class="nokern relpos" data-width="256.259766" style="left:9.593px;top:65.192px;">Alpha-Standard Security Protocol — L4 Authorization Code Handling</span></div></div><div id="svg7_20581c0" style="left:51.822px;top:201.271px;"><svg width="694" height="3" viewBox="-1.333 -0.667 694 3"><g fill="#1e2761" stroke="none"><path stroke="#1e2761" stroke-width="1.333" stroke-linecap="butt" transform="translate(-53.155457,-201.937836)" d="M53.155,202.605 H743.529"/></g></svg></div><div id="spr8_20581c0" style="left:53.155px;top:207.411px;"><div style="width:0px;"><span id="txt10_20581c0" class="nokern" data-width="55.580078" style="left:9.6px;top:7.651px;">1. PURPOSE</span></div><div style="width:0px;"><span id="txt11_20581c0" class="nokern" data-width="665.607422" style="left:9.6px;top:29.514px;">This memorandum establishes mandatory handling procedures for Level 4 (L4) authorization codes under the Alpha-Standard Security Protocol.</span></div><div style="width:0px;"><span id="txt12_20581c0" class="nokern" data-width="280.235046" style="left:9.6px;top:45.953px;">Compliance is non-negotiable and binding upon all personnel.</span></div><div style="width:0px;"><span id="txt13_20581c0" class="nokern" data-width="45.117188" style="left:9.6px;top:71.651px;">2. SCOPE</span></div><div style="width:0px;"><span id="txt14_20581c0" class="nokern" data-width="641.237000" style="left:9.6px;top:93.514px;">This directive applies to all Alpha Corp. personnel, contractors, consultants, and third-party affiliates with access to L4-classified systems,</span></div><div style="width:0px;"><span id="txt15_20581c0" class="nokern" data-width="233.434906" style="left:9.6px;top:109.953px;">regardless of department, clearance level, or title.</span></div><div style="width:0px;"><span id="txt16_20581c0" data-width="52.226562" style="left:9.6px;top:134.364px;">3. POLICY</span></div><div style="width:0px;"><span id="txt17_20581c0" data-width="649.867188" style="left:9.6px;top:155.711px;">L4 authorization codes shall NOT, under any circumstances, be communicated, transmitted, or disclosed via voice calls,</span></div><div style="width:0px;"><span id="txt18_20581c0" data-width="618.234375" style="left:9.6px;top:172.417px;">video calls, or any real-time verbal communication channel. This prohibition is absolute and applies regardless of:</span></div><div style="width:0px;"><span id="txt19_20581c0" class="nokern relpos" dir="auto" style="left:57.683px;top:193.732px;">•</span> <span id="txt20_20581c0" class="relpos" data-width="239.882812" style="left:57.683px;top:193.044px;"> The identity or rank of the requesting party</span></div><div style="width:0px;"><span id="txt21_20581c0" class="nokern relpos" dir="auto" style="left:57.683px;top:211.065px;">•</span> <span id="txt22_20581c0" class="relpos" data-width="246.468750" style="left:57.683px;top:210.377px;"> Claims of urgency or operational emergency</span></div><div style="width:0px;"><span id="txt23_20581c0" class="nokern relpos" dir="auto" style="left:57.683px;top:227.771px;">•</span> <span id="txt24_20581c0" class="relpos" data-width="392.585938" style="left:57.683px;top:227.084px;"> Direct requests from executive leadership, officers, or board members</span></div><div style="width:0px;"><span id="txt25_20581c0" data-width="669.906250" style="left:9.6px;top:247.711px;">No executive, officer, or manager — regardless of title or seniority — possesses the authority to override this protocol via</span></div><div style="width:0px;"><span id="txt26_20581c0" class="relpos" data-width="80.421875" style="left:9.6px;top:264.068px;">verbal request</span> <span id="txt27_20581c0" class="nokern relpos" style="left:9.593px;top:268.573px;">.</span></div><div style="width:0px;"><span id="txt28_20581c0" class="nokern" data-width="68.808594" style="left:9.6px;top:292.939px;">4. COMPLIANCE</span></div><div style="width:0px;"><span id="txt29_20581c0" class="nokern" data-width="670.770874" style="left:9.6px;top:312.998px;">Violations will result in immediate suspension of system access, mandatory security review, and potential disciplinary action up to and</span></div><div style="width:0px;"><span id="txt30_20581c0" class="nokern" data-width="245.151047" style="left:9.6px;top:329.355px;">including termination of employment or contract.</span></div><div style="width:0px;"><span id="txt31_20581c0" class="nokern" data-width="76.152344" style="left:9.6px;top:356.939px;">5. ENFORCEMENT</span></div><div style="width:0px;"><span id="txt32_20581c0" data-width="652.184875" style="left:9.6px;top:373.825px;">The Office of the CISO retains sole authority to amend or grant exceptions to this policy. All exceptions must be</span></div><div style="width:0px;"><span id="txt33_20581c0" data-width="317.078125" style="left:9.6px;top:391.158px;">documented in writing and countersigned by the CISO.</span></div></div><div id="svg10_20581c0" style="left:67.822px;top:642.388px;"><svg width="678" height="3" viewBox="-1.333 -0.667 678 3"><g fill="#1e2761" stroke="none"><path stroke="#1e2761" stroke-width="1.333" stroke-linecap="butt" transform="translate(-69.155518,-643.05426)" d="M69.155,643.721 H743.529"/></g></svg></div><div id="spr9_20581c0" style="left:380.728px;top:643.721px;"><div style="width:0px;"><span id="txt34_20581c0" class="nokern" data-width="73.209633" style="left:9.6px;top:5.181px;">AUTHORIZED BY:</span></div><div style="width:0px;"><span id="txt35_20581c0" class="nokern" data-width="341.178375" style="left:9.6px;top:21.648px;">Office of the Chief Information Security Officer  |  Alpha Corp. — Security Division</span></div></div><div id="spr10_20581c0" style="left:779.25px;top:330.75px;"><img id="img3_20581c0" src="data:image/png;base64," width="441.75" height="58.5" alt="SOURCE OF TRUTH\
"/></div><a id="hl0_20581c0" href="#" onclick="document.getElementById(\'coreSpr_33896453\').getCore().processTriggerEffect(this);document.getElementById(\'coreSpr_33896453\').getCore().gotoSlide(2, this);return false;" style="left:1124.716px;top:664.627px;"><img id="img4_20581c0" src="data:image/png;base64," width="113.344" height="39.521" alt=""/></a><div id="spr11_20581c0" style="left:1124.716px;top:664.627px;"><div style="width:0px;"><a id="hl1_20581c0" class="relpos" href="#" onclick="document.getElementById(\'coreSpr_33896453\').getCore().processTriggerEffect(this);document.getElementById(\'coreSpr_33896453\').getCore().gotoSlide(2, this);return false;"><span id="txt36_20581c0" class="relpos" data-width="51.363281" style="left:28.767px;top:1.764px;">NEXT</span></a><a id="hl2_20581c0" class="relpos" href="#" onclick="document.getElementById(\'coreSpr_33896453\').getCore().processTriggerEffect(this);document.getElementById(\'coreSpr_33896453\').getCore().gotoSlide(2, this);return false;"><span id="txt37_20581c0" class="relpos" style="left:28.76px;top:5.69px;"></span></a></div></div></div></div>', '{"s":[]}');})();